\frac{1}{z} +\frac{1}{w} &=& \frac{w}{wz} + \frac{z}{wz}\\
&=& \frac{w + z}{wz}\\
&=& \frac{w + z}{3i}
\end{eqnarray*} 
which leads to
\begin{eqnarray*}
\frac{1}{z} + \frac{1}{w} &=& \frac{(w + z) \times (3i)}{wz \times (3i)}\\ 
&=& 
\frac{ - 3i \times (w + z) }{ - 3i \times 3i}\\ 
&=& \frac{w + z}{3}\\ 
&=& \frac{-2}{3} 
\end{eqnarray*}
\begin{eqnarray*}
\left | \frac{1}{z} + \frac{1}{w} \right| &=& \left |\frac{-2}{3} \right | = \frac{2}{3}
\end{eqnarray*>
